/**
 * API route for triggering on-demand schema inference for a dataset.
 *
 * This endpoint allows editors and admins to generate a schema for datasets
 * that weren't created through the import pipeline (e.g., seeding, direct
 * event creation via API).
 *
 * Access control:
 * - Editors and admins can infer schema for any dataset
 * - Schema is generated by sampling existing events in the dataset
 *
 * @module
 * @category API
 */
import { z } from "zod";

import { apiRoute, NotFoundError, requirePrivileged, ValidationError } from "@/lib/api";
import { SchemaInferenceService } from "@/lib/ingest/schema-inference";
import { logger } from "@/lib/logger";
import type { SchemaInferenceResponse } from "@/lib/types/schema-inference";
import { parseStrictInteger } from "@/lib/utils/event-params";

export type { SchemaInferenceOptions, SchemaInferenceResponse } from "@/lib/types/schema-inference";

const schemaInferBody = z.object({
  sampleSize: z.number().int().positive().optional(),
  batchSize: z.number().int().positive().optional(),
  forceRegenerate: z.boolean().optional(),
});

export const POST = apiRoute({
  auth: "required",
  params: z.object({ id: z.string() }),
  body: schemaInferBody,
  handler: async ({ user, payload, params, body }) => {
    const datasetId = parseStrictInteger(params.id);

    if (datasetId == null) {
      throw new ValidationError("Invalid dataset ID");
    }

    // Check user permissions - only editors and admins can infer schema
    requirePrivileged(user);

    // Verify dataset exists and user has access
    const dataset = await payload
      .findByID({ collection: "datasets", id: datasetId, overrideAccess: false, user })
      .catch(() => null);

    if (!dataset) {
      throw new NotFoundError("Dataset not found");
    }

    const options = body;

    logger.info({ datasetId, userId: user.id, options }, "Schema inference requested");

    // Perform schema inference
    const result = await SchemaInferenceService.inferSchemaFromEvents(payload, datasetId, options);

    logger.info(
      { datasetId, userId: user.id, generated: result.generated, eventsSampled: result.eventsSampled },
      "Schema inference completed"
    );

    return {
      generated: result.generated,
      message: result.message,
      eventsSampled: result.eventsSampled,
      schema: result.schema
        ? {
            id: result.schema.id,
            versionNumber: result.schema.versionNumber,
            createdAt: result.schema.createdAt,
            eventCountAtCreation: result.schema.eventCountAtCreation ?? undefined,
          }
        : null,
    } satisfies SchemaInferenceResponse;
  },
});
